    17→import SessionRecap from "@/components/mirror/SessionRecap";
    18→import { socket } from "@/lib/socket";
    19→import { skipQueueUser } from "@/lib/api";
    20→import type { DetectedGesture, GestureType } from "@/types/gestures";
    21→import type { PoseResult } from "@/types/pose";
    22→import type { ClothingItem } from "@/types/clothing";
    23→import { mapToClothingItems } from "@/lib/map-clothing-items";
    24→
    25→type KioskState = "attract" | "waiting" | "session" | "recap";
    26→
    27→interface ActiveUser {
    28→  id: string;
    29→  name: string;
    30→}
    31→
    32→const PHONE_URL = process.env.NEXT_PUBLIC_PHONE_URL || "https://mirrorless.vercel.app/phone";
    33→const WAITING_TIMEOUT_MS = 2 * 60 * 1000; // 2 minutes
    34→
    35→export default function MirrorPageWrapper() {
    36→  return (
    37→    <Suspense fallback={null}>
    38→      <MirrorPage />
    39→    </Suspense>
    40→  );
    41→}
    42→
    43→function MirrorPage() {
    44→  // Kiosk state
    45→  const [kioskState, setKioskState] = useState<KioskState>("attract");
    46→  const [activeUser, setActiveUser] = useState<ActiveUser | null>(null);
    47→  const waitingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    48→  const pendingQueueRef = useRef<ActiveUser | null | undefined>(undefined);
    49→
    50→  // Camera + gesture recognition
    51→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    52→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    53→  const gestureKeyRef = useRef(0);
    54→  const [gestureKey, setGestureKey] = useState(0);
    55→
    56→  // Session state
    57→  const [sessionActive, setSessionActive] = useState(false);
    58→  const [isStarting, setIsStarting] = useState(false);
    59→
    60→  // Pose detection + clothing overlay state
    61→  const [currentPose, setCurrentPose] = useState<PoseResult | null>(null);
    62→
    63→  interface CanvasOutfit {
    64→    name: string;
    65→    items: ClothingItem[];
    66→    productInfo: PriceStripItem[];
    67→  }
    68→  const [canvasOutfits, setCanvasOutfits] = useState<CanvasOutfit[]>([]);
    69→  const [canvasOutfitIndex, setCanvasOutfitIndex] = useState(0);
    70→  const activeCanvasOutfit = canvasOutfits[canvasOutfitIndex]?.items ?? [];
    71→  const activePriceItems = canvasOutfits[canvasOutfitIndex]?.productInfo ?? [];
    72→
    73→  // Recap state (shown after session ends)
    74→  const [recapData, setRecapData] = useState<{
    75→    summary?: string;
    76→    liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
    77→    stats?: { items_shown: number; likes: number; dislikes: number };
    78→    user_name?: string;
    79→  } | null>(null);
    80→
    81→  // Mira video avatar + voice
    82→  const mira = useMiraVideoAvatar();
    83→  const stt = useDeepgramSTT();
    84→
    85→  // Queue transcripts while mira is speaking, send when quiet
    86→  const pendingTranscriptRef = useRef<string | null>(null);
    87→
    88→  // Accumulate full response text before delivering
    89→  const responseAccumulatorRef = useRef<string>("");
    90→
    91→  // Current user ID for session (from queue, not URL)
    92→  const userId = activeUser?.id ?? null;
    93→
    94→  // Pose detection for clothing overlay
    95→  const handlePoseUpdate = useCallback((result: PoseResult) => {
    96→    setCurrentPose(result);
    97→  }, []);
    98→
    99→  usePoseDetection({
   100→    videoRef,
   101→    isVideoReady: isCameraReady,
   102→    onPoseUpdate: handlePoseUpdate,
   103→  });
   104→
   105→  // Connect socket and join mirror room
   106→  useEffect(() => {
   107→    socket.connect();
   108→    socket.emit("join_mirror_room");
   109→
   110→    return () => {
   111→      socket.disconnect();
   112→    };
   113→  }, []);
   114→
   115→  // Join user-specific room when active user changes
   116→  useEffect(() => {
   117→    if (userId) {
   118→      socket.emit("join_room", { user_id: userId });
   119→    }
   120→  }, [userId]);
   121→
   122→  // Listen for queue_updated events (drives attract ↔ waiting transitions)
   123→  useEffect(() => {
   124→    const handleQueueUpdated = (data: {
   125→      active_user: ActiveUser | null;
   126→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   127→    }) => {
   128→      console.log("[Mirror] queue_updated:", data);
   129→      if (kioskState === "session") return; // Don't interrupt active sessions
   130→
   131→      // During recap, store the update for when recap dismisses
   132→      if (kioskState === "recap") {
   133→        pendingQueueRef.current = data.active_user ?? null;
   134→        return;
   135→      }
   136→
   137→      if (data.active_user) {
   138→        setActiveUser(data.active_user);
   139→        setKioskState("waiting");
   140→      } else {
   141→        setActiveUser(null);
   142→        setKioskState("attract");
   143→      }
   144→    };
   145→
   146→    socket.on("queue_updated", handleQueueUpdated);
   147→    return () => {
   148→      socket.off("queue_updated", handleQueueUpdated);
   149→    };
   150→  }, [kioskState]);
   151→
   152→  // 2-minute timeout in waiting state
   153→  useEffect(() => {
   154→    if (kioskState === "waiting" && activeUser) {
   155→      waitingTimerRef.current = setTimeout(() => {
   156→        console.log("[Mirror] Waiting timeout — auto-skipping user");
   157→        skipQueueUser(activeUser.id).catch(() => {});
   158→      }, WAITING_TIMEOUT_MS);
   159→    }
   160→    return () => {
   161→      if (waitingTimerRef.current) {
   162→        clearTimeout(waitingTimerRef.current);
   163→        waitingTimerRef.current = null;
   164→      }
   165→    };
   166→  }, [kioskState, activeUser]);
   167→
   168→  // Listen for session_active from backend
   169→  useEffect(() => {
   170→    const handleSessionActive = () => {
   171→      setKioskState("session");
   172→      setSessionActive(true);
   173→      setIsStarting(false);
   174→      setCanvasOutfits([]);
   175→      setCanvasOutfitIndex(0);
   176→      mira.startSession();
   177→      stt.startListening();
   178→    };
   179→
   180→    socket.on("session_active", handleSessionActive);
   181→    return () => {
   182→      socket.off("session_active", handleSessionActive);
   183→    };
   184→    // eslint-disable-next-line react-hooks/exhaustive-deps
   185→  }, []);
   186→
   187→  // Listen for mira_speech events (streamed text from AI)
   188→  useEffect(() => {
   189→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   190→      // Fallback session detection
   191→      if (!sessionActive && !isStarting) {
   192→        setKioskState("session");
   193→        setSessionActive(true);
   194→        setIsStarting(false);
   195→        mira.startSession();
   196→        stt.startListening();
   197→      }
   198→
   199→      if (data.is_chunk !== false) {
   200→        if (!data.text) return;
   201→        console.log("[Mirror] mira_speech chunk received");
   202→        responseAccumulatorRef.current += data.text;
   203→        mira.setOrbState("thinking");
   204→        mira.setEmotion("thinking");
   205→      } else {
   206→        if (data.text) {
   207→          responseAccumulatorRef.current += data.text;
   208→        }
   209→        const fullText = responseAccumulatorRef.current;
   210→        responseAccumulatorRef.current = "";
   211→        console.log("[Mirror] Agent full response:", fullText);
   212→        if (!fullText) return;
   213→
   214→        // Parse emotion tag first, then detect from content as fallback
   215→        let { emotion, cleanText } = parseEmotionTag(fullText);
   216→
   217→        // If no explicit emotion tag, try to detect from content
   218→        if (emotion === "idle") {
   219→          emotion = detectEmotionFromText(cleanText);
   220→        }
   221→
   222→        console.log("[Mirror] Parsed emotion:", emotion);
   223→        mira.speak(cleanText, emotion);
   224→      }
   225→    };
   226→
   227→    socket.on("mira_speech", handleSpeech);
   228→    return () => {
   229→      socket.off("mira_speech", handleSpeech);
   230→    };
   231→    // eslint-disable-next-line react-hooks/exhaustive-deps
   232→  }, [sessionActive, isStarting]);
   233→
   234→  // Listen for tool_result events (product recommendations + voice messages)
   235→  useEffect(() => {
   236→    const handleToolResult = (data: {
   237→      type?: string;
   238→      tool?: string;
   239→      items?: { title: string; price?: string; [key: string]: unknown }[];
   240→      text?: string;
   241→      emotion?: string;
   242→      outfit_name?: string;
   243→    }) => {
   244→      if (data.type === "display_product" && data.items) {
   245→        const clothingItems = mapToClothingItems(data.items);
   246→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   247→          title: it.title,
   248→          price: it.price,
   249→        }));
   250→        if (clothingItems.length > 0) {
   251→          setCanvasOutfits((prev) => {
   252→            const next = [...prev, {
   253→              name: data.outfit_name || `Outfit ${prev.length + 1}`,
   254→              items: clothingItems,
   255→              productInfo: priceInfo,
   256→            }];
   257→            setCanvasOutfitIndex(next.length - 1);
   258→            return next;
   259→          });
   260→        }
   261→        return;
   262→      }
   263→      if (data.type === "voice_message" && data.text) {
   264→        const emotion = detectEmotionFromText(data.text);
   265→        mira.speak(data.text, emotion);
   266→        return;
   267→      }
   268→    };
   269→
   270→    socket.on("tool_result", handleToolResult);
   271→    return () => {
   272→      socket.off("tool_result", handleToolResult);
   273→    };
   274→    // eslint-disable-next-line react-hooks/exhaustive-deps
   275→  }, [mira.speak]);
   276→
   277→  // Listen for session_ended — show recap overlay, then return to attract
   278→  useEffect(() => {
   279→    const handleSessionEnded = (data?: {
   280→      summary?: string;
   281→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   282→      stats?: { items_shown: number; likes: number; dislikes: number };
   283→      user_name?: string;
   284→    }) => {
   285→      // Don't stop mira immediately — let closing speech TTS finish playing
   286→      stt.stopListening();
   287→      setSessionActive(false);
   288→      setCanvasOutfits([]);
   289→      setCanvasOutfitIndex(0);
   290→
   291→      // Show recap overlay (keep activeUser set for display)
   292→      if (data && (data.summary || data.liked_items?.length || data.stats)) {
   293→        setRecapData(data);
   294→        setKioskState("recap");
   295→      } else {
   296→        // No recap data — go straight to attract
   297→        mira.stopSession();
   298→        setActiveUser(null);
   299→        setKioskState("attract");
   300→      }
   301→    };
   302→
   303→    socket.on("session_ended", handleSessionEnded);
   304→    return () => {
   305→      socket.off("session_ended", handleSessionEnded);
   306→    };
   307→    // eslint-disable-next-line react-hooks/exhaustive-deps
   308→  }, []);
   309→
   310→  // Listen for session_force_end — same as session_ended
   311→  useEffect(() => {
   312→    const handleForceEnd = (data: { user_id?: string }) => {
   313→      if (userId && data.user_id === userId) {
   314→        socket.emit("end_session", { user_id: userId });
   315→      }
   316→    };
   317→
   318→    socket.on("session_force_end", handleForceEnd);
   319→    return () => {
   320→      socket.off("session_force_end", handleForceEnd);
   321→    };
   322→  }, [userId]);
   323→
   324→  // Send transcripts to backend when mira stops speaking
   325→  useEffect(() => {
   326→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   327→      console.log("[Mirror] Flushing queued transcript:", pendingTranscriptRef.current);
   328→      socket.emit("mirror_event", {
   329→        user_id: userId,
   330→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   331→      });
   332→      pendingTranscriptRef.current = null;
   333→    }
   334→  }, [mira.isSpeaking, userId]);
   335→
   336→  // Forward final STT transcripts
   337→  useEffect(() => {
   338→    if (!stt.transcript || !userId) return;
   339→
   340→    if (mira.isSpeaking) {
   341→      console.log("[Mirror] Queuing transcript (mira speaking):", stt.transcript);
   342→      pendingTranscriptRef.current = stt.transcript;
   343→    } else {
   344→      console.log("[Mirror] Sending transcript to backend:", stt.transcript);
   345→      socket.emit("mirror_event", {
   346→        user_id: userId,
   347→        event: { type: "voice", transcript: stt.transcript },
   348→      });
   349→    }
   350→    // eslint-disable-next-line react-hooks/exhaustive-deps
   351→  }, [stt.transcript, userId]);
   352→
   353→  // Listen for snapshot requests from the backend
   354→  useEffect(() => {
   355→    const handleSnapshotRequest = () => {
   356→      const video = videoRef.current;
   357→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   358→
   359→      const canvas = document.createElement("canvas");
   360→      canvas.width = video.videoWidth;
   361→      canvas.height = video.videoHeight;
   362→      const ctx = canvas.getContext("2d");
   363→      if (!ctx) return;
   364→
   365→      ctx.drawImage(video, 0, 0);
   366→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   367→      const base64 = dataUrl.split(",")[1];
   368→
   369→      socket.emit("mirror_event", {
   370→        type: "snapshot",
   371→        image_base64: base64,
   372→        user_id: userId,
   373→      });
   374→    };
   375→
   376→    socket.on("request_snapshot", handleSnapshotRequest);
   377→    return () => {
   378→      socket.off("request_snapshot", handleSnapshotRequest);
   379→    };
   380→  }, [videoRef, userId]);
   381→
   382→  // Gesture handler
   383→  const handleGesture = useCallback(
   384→    (gesture: DetectedGesture) => {
   385→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   386→
   387→      setLastGesture(gesture.type);
   388→      gestureKeyRef.current += 1;
   389→      setGestureKey(gestureKeyRef.current);
   390→
   391→      if (canvasOutfits.length > 1) {
   392→        if (gesture.type === "swipe_left") {
   393→          setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   394→        } else if (gesture.type === "swipe_right") {
   395→          setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   396→        }
   397→      }
   398→
   399→      socket.emit("mirror_event", {
   400→        user_id: userId,
   401→        event: {
   402→          type: "gesture",
   403→          gesture: gesture.type,
   404→          confidence: gesture.confidence,
   405→          timestamp: gesture.timestamp,
   406→        },
   407→      });
   408→    },
   409→    [userId, canvasOutfits.length],
   410→  );
   411→
   412→  const { isLoading: isModelLoading, error: modelError } =
   413→    useGestureRecognizer({
   414→      videoRef,
   415→      isVideoReady: isCameraReady,
   416→      onGesture: handleGesture,
   417→    });
