   419→  const handleStartSession = useCallback(() => {
   420→    if (!userId || isStarting || sessionActive) return;
   421→
   422→    // Unlock browser audio policy while we still have the user gesture context
   423→    const ctx = new AudioContext();
   424→    ctx.resume().then(() => ctx.close());
   425→
   426→    setIsStarting(true);
   427→
   428→    // Emit start via socket (server-side orchestrator)
   429→    socket.emit("start_session", { user_id: userId });
   430→  }, [userId, isStarting, sessionActive]);
   431→
   432→  const handleSkipUser = useCallback(() => {
   433→    if (!activeUser) return;
   434→    skipQueueUser(activeUser.id).catch(() => {});
   435→  }, [activeUser]);
   436→
   437→  // Dismiss recap overlay — transition to next queued user or attract
   438→  const handleRecapDismiss = useCallback(() => {
   439→    mira.stopSession();
   440→    setRecapData(null);
   441→
   442→    // Check if a queue_updated arrived during recap
   443→    const pending = pendingQueueRef.current;
   444→    pendingQueueRef.current = undefined;
   445→
   446→    if (pending) {
   447→      setActiveUser(pending);
   448→      setKioskState("waiting");
   449→    } else {
   450→      setActiveUser(null);
   451→      setKioskState("attract");
   452→    }
   453→    // eslint-disable-next-line react-hooks/exhaustive-deps
   454→  }, []);
   455→
   456→  return (
   457→    <main
