   468→        ref={videoRef}
   469→        autoPlay
   470→        playsInline
   471→        muted
   472→        style={{
   473→          position: "absolute",
   474→          top: 0,
   475→          left: 0,
   476→          width: "100%",
   477→          height: "100%",
   478→          objectFit: "cover",
   479→          transform: "scaleX(-1)",
   480→        }}
   481→      />
   482→
   483→      {/* === ATTRACT STATE === */}
   484→      {kioskState === "attract" && (
