   525→              includeMargin={false}
   526→            />
   527→          </div>
   528→
   529→          <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "0.9rem" }}>
   530→            Scan the QR code with your phone
   531→          </p>
   532→        </div>
   533→      )}
   534→
   535→      {/* === WAITING STATE === */}
   536→      {kioskState === "waiting" && activeUser && (
   537→        <div
   538→          style={{
   539→            position: "absolute",
   540→            inset: 0,
   541→            zIndex: 20,
   542→            display: "flex",
   543→            flexDirection: "column",
   544→            alignItems: "center",
   545→            justifyContent: "center",
   546→            background: "rgba(0,0,0,0.6)",
   547→            backdropFilter: "blur(10px)",
   548→          }}
