     1→/**
     2→ * Streaming TTS client using ElevenLabs REST streaming endpoint.
     3→ *
     4→ * Uses fetch + ReadableStream + MediaSource API for low-latency audio playback.
     5→ * Extracts real-time volume via AudioContext + AnalyserNode for Orb visualization.
     6→ */
     7→
     8→export class StreamingTTS {
     9→  private apiUrl: string;
    10→  private generation = 0;
    11→  private speaking = false;
    12→  private audio: HTMLAudioElement | null = null;
    13→  private mediaSource: MediaSource | null = null;
    14→  private audioContext: AudioContext | null = null;
    15→  private analyser: AnalyserNode | null = null;
    16→  private sourceNode: MediaElementAudioSourceNode | null = null;
    17→  private frequencyData: Uint8Array<ArrayBuffer> | null = null;
    18→  private pendingResolve: (() => void) | null = null;
    19→
    20→  constructor(apiUrl: string) {
    21→    this.apiUrl = apiUrl;
    22→  }
    23→
    24→  /**
    25→   * Stream TTS audio for the given text.
    26→   * Returns a promise that resolves when playback finishes.
    27→   */
    28→  async speak(
    29→    text: string,
    30→    onStart?: () => void,
    31→    onEnd?: () => void,
    32→  ): Promise<void> {
    33→    const gen = ++this.generation;
    34→
    35→    try {
    36→      this.speaking = true;
    37→
    38→      const resp = await fetch(`${this.apiUrl}/api/tts/stream`, {
    39→        method: "POST",
    40→        headers: { "Content-Type": "application/json" },
    41→        body: JSON.stringify({ text }),
    42→      });
    43→
    44→      if (this.generation !== gen) {
    45→        this.speaking = false;
    46→        return;
    47→      }
    48→
    49→      if (!resp.ok || !resp.body) {
    50→        throw new Error(`TTS stream failed: ${resp.status}`);
    51→      }
    52→
    53→      await this.playStream(resp.body, gen, onStart, onEnd);
    54→    } catch (err) {
    55→      console.error("[StreamingTTS] Error:", err);
    56→      this.speaking = false;
    57→      onEnd?.();
    58→    }
    59→  }
    60→
    61→  private async playStream(
    62→    body: ReadableStream<Uint8Array>,
    63→    gen: number,
    64→    onStart?: () => void,
    65→    onEnd?: () => void,
    66→  ): Promise<void> {
    67→    return new Promise<void>((resolve) => {
    68→      this.pendingResolve = resolve;
    69→
    70→      const mediaSource = new MediaSource();
    71→      this.mediaSource = mediaSource;
    72→
    73→      const audio = new Audio();
    74→      this.audio = audio;
    75→      audio.src = URL.createObjectURL(mediaSource);
    76→
    77→      // Connect to AudioContext for volume analysis
    78→      this.connectAnalyser(audio);
    79→
    80→      let settled = false;
    81→      const done = () => {
    82→        if (settled) return;
    83→        settled = true;
    84→        this.pendingResolve = null;
    85→        this.speaking = false;
    86→        if (audio.src) {
    87→          URL.revokeObjectURL(audio.src);
    88→        }
    89→        onEnd?.();
    90→        resolve();
    91→      };
    92→
    93→      audio.onerror = done;
    94→      audio.onended = done;
    95→
    96→      mediaSource.addEventListener("sourceopen", () => {
    97→        if (this.generation !== gen) {
    98→          done();
    99→          return;
   100→        }
   101→
   102→        let sourceBuffer: SourceBuffer;
   103→        try {
   104→          sourceBuffer = mediaSource.addSourceBuffer("audio/mpeg");
   105→        } catch {
   106→          console.error("[StreamingTTS] Failed to add source buffer");
   107→          done();
   108→          return;
   109→        }
   110→
   111→        const reader = body.getReader();
   112→        let started = false;
   113→
   114→        const pump = async () => {
   115→          try {
   116→            const { done: readerDone, value } = await reader.read();
   117→
   118→            if (this.generation !== gen) {
   119→              reader.cancel();
   120→              if (mediaSource.readyState === "open") {
   121→                mediaSource.endOfStream();
   122→              }
   123→              done();
   124→              return;
   125→            }
   126→
   127→            if (readerDone) {
   128→              if (mediaSource.readyState === "open" && !sourceBuffer.updating) {
   129→                mediaSource.endOfStream();
   130→              } else if (mediaSource.readyState === "open") {
   131→                sourceBuffer.addEventListener(
   132→                  "updateend",
   133→                  () => {
   134→                    if (mediaSource.readyState === "open") {
   135→                      mediaSource.endOfStream();
   136→                    }
   137→                  },
   138→                  { once: true },
   139→                );
   140→              }
   141→              console.log("[StreamingTTS] Stream complete");
   142→              return;
   143→            }
   144→
   145→            if (sourceBuffer.updating) {
   146→              // Wait for the current update to finish before appending
   147→              await new Promise<void>((res) => {
   148→                sourceBuffer.addEventListener("updateend", () => res(), {
   149→                  once: true,
   150→                });
   151→              });
   152→            }
   153→
   154→            sourceBuffer.appendBuffer(value as unknown as BufferSource);
   155→
   156→            if (!started) {
   157→              started = true;
   158→              console.log("[StreamingTTS] Playback starting");
   159→              onStart?.();
   160→              audio.play().catch(() => {
   161→                console.warn("[StreamingTTS] Autoplay blocked");
   162→              });
   163→            }
   164→
   165→            sourceBuffer.addEventListener("updateend", () => pump(), {
   166→              once: true,
   167→            });
   168→          } catch (err) {
   169→            console.error("[StreamingTTS] Pump error:", err);
   170→            done();
   171→          }
   172→        };
   173→
   174→        pump();
   175→      });
   176→    });
   177→  }
   178→
   179→  private connectAnalyser(audio: HTMLAudioElement): void {
   180→    try {
   181→      if (!this.audioContext) {
   182→        this.audioContext = new AudioContext();
   183→        this.analyser = this.audioContext.createAnalyser();
   184→        this.analyser.fftSize = 256;
   185→        this.analyser.smoothingTimeConstant = 0.7;
   186→        this.analyser.connect(this.audioContext.destination);
   187→        this.frequencyData = new Uint8Array(this.analyser.frequencyBinCount);
   188→      }
   189→
   190→      // Resume context if suspended (browser autoplay policy)
   191→      if (this.audioContext.state === "suspended") {
   192→        this.audioContext.resume();
   193→      }
   194→
   195→      // createMediaElementSource can only be called once per element,
   196→      // so we disconnect the old source and create a new one
   197→      if (this.sourceNode) {
   198→        this.sourceNode.disconnect();
   199→        this.sourceNode = null;
   200→      }
   201→
   202→      const source = this.audioContext.createMediaElementSource(audio);
   203→      source.connect(this.analyser!);
   204→      this.sourceNode = source;
   205→    } catch (err) {
   206→      console.warn("[StreamingTTS] AudioContext setup failed:", err);
   207→    }
   208→  }
   209→
   210→  /**
   211→   * Get current output volume (0-1) for feeding to the Orb component.
   212→   * Uses the same power-curve normalization as ElevenLabs SDK.
   213→   */
   214→  getOutputVolume(): number {
   215→    if (!this.analyser || !this.frequencyData || !this.speaking) return 0;
   216→
   217→    this.analyser.getByteFrequencyData(this.frequencyData);
   218→
   219→    let sum = 0;
   220→    for (let i = 0; i < this.frequencyData.length; i++) {
   221→      sum += this.frequencyData[i];
   222→    }
   223→    const raw = sum / (this.frequencyData.length * 255);
   224→
   225→    // Power-curve normalization (same as ElevenLabs SDK voice-chat blocks)
   226→    return Math.min(1.0, Math.pow(raw, 0.5) * 2.5);
   227→  }
   228→
   229→  /** Stop current playback and cancel any in-flight stream. */
   230→  stop(): void {
   231→    this.generation++;
   232→    this.speaking = false;
   233→
   234→    if (this.audio) {
   235→      this.audio.pause();
   236→      if (this.audio.src) {
   237→        URL.revokeObjectURL(this.audio.src);
   238→      }
   239→      this.audio = null;
   240→    }
   241→
   242→    if (this.mediaSource?.readyState === "open") {
   243→      try {
   244→        this.mediaSource.endOfStream();
   245→      } catch {
   246→        // Already ended
   247→      }
   248→    }
   249→    this.mediaSource = null;
   250→
   251→    if (this.pendingResolve) {
   252→      this.pendingResolve();
   253→      this.pendingResolve = null;
   254→    }
   255→  }
   256→
   257→  isSpeaking(): boolean {
   258→    return this.speaking;
   259→  }
   260→
   261→  /** Clean up AudioContext on teardown. */
   262→  destroy(): void {
   263→    this.stop();
   264→    if (this.sourceNode) {
   265→      this.sourceNode.disconnect();
   266→      this.sourceNode = null;
   267→    }
   268→    if (this.audioContext) {
   269→      this.audioContext.close();
   270→      this.audioContext = null;
   271→    }
   272→    this.analyser = null;
   273→    this.frequencyData = null;
   274→  }
   275→}
